        data: {"result": {"minY": 1.0, "minX": 0.0, "maxY": 100.0, "series": [{"data": [[100.0, 35.0]], "isOverall": false, "label": "1.2 Sign-in page", "isController": false}, {"data": [[0.0, 100.0]], "isOverall": false, "label": "2.0 Register attendance", "isController": true}, {"data": [[2500.0, 1.0], [1700.0, 20.0], [1800.0, 10.0], [1900.0, 2.0], [2000.0, 2.0]], "isOverall": false, "label": "1.0 Login", "isController": true}, {"data": [[300.0, 1.0], [200.0, 16.0], [100.0, 18.0]], "isOverall": false, "label": "1.5 Open Sessions list", "isController": false}, {"data": [[300.0, 35.0]], "isOverall": false, "label": "1.4 Select Organisations", "isController": false}, {"data": [[700.0, 1.0], [400.0, 33.0], [500.0, 1.0]], "isOverall": false, "label": "1.1 Homepage", "isController": false}, {"data": [[600.0, 17.0], [700.0, 1.0], [800.0, 1.0], [1000.0, 1.0], [500.0, 15.0]], "isOverall": false, "label": "1.3 Sign-in", "isController": false}, {"data": [[0.0, 100.0]], "isOverall": false, "label": "2.1 Open session", "isController": false}], "supportsControllersDiscrimination": true, "granularity": 100, "maxX": 2500.0, "title": "Response Time Distribution"}},
